class Solution {
public:
    string maximumBinaryString(string binary) {
        int n = binary.length();
        int left = 0;
        int zeros = 0;

        while (left < n && binary[left] == '1') {
            left++;
        }

        for (int i = left; i < n; ++i) {
            if (binary[i] == '0') {
                ++zeros;
            }
        }

        if (zeros <= 1) {
            return binary;
        }

        int firstZero = left;
        int onesBefore = left;

        for (int i = firstZero; i < n - 1; ++i) {
            if (binary[i] == '0' && binary[i + 1] == '0') {
                binary[i] = '1';
                int j = i + 1;
                while (j < n && binary[j] == '1') {
                    ++j;
                }
                if (j < n) {
                    binary[j] = '0';
                }
            }
        }

        return binary;
    }
};

